import{_ as t,o as n,c as i,a3 as a}from"./chunks/framework.CjquFG0V.js";const g=JSON.parse('{"title":"74. Statewide Industry Panel","description":"","frontmatter":{"title":"74. Statewide Industry Panel","eba":"Health Allied & Managers Admin 2021-2025","topics":["disputes","preliminary","classifications"]},"headers":[],"relativePath":"ebas/has-managers-admin/common-terms/union-matters/74-statewide-industry-panel.md","filePath":"ebas/has-managers-admin/common-terms/union-matters/74-statewide-industry-panel.md"}'),o={name:"ebas/has-managers-admin/common-terms/union-matters/74-statewide-industry-panel.md"};function r(s,e,p,l,d,h){return n(),i("div",null,[...e[0]||(e[0]=[a('<h1 id="_74-statewide-industry-panel" tabindex="-1">74. Statewide Industry Panel <a class="header-anchor" href="#_74-statewide-industry-panel" aria-label="Permalink to &quot;74. Statewide Industry Panel&quot;">​</a></h1><p><strong>74.1</strong> Application</p><p><strong>(a)</strong> This Statewide Industry Panel (Panel) can undertake the following functions:</p><p><strong>(i)</strong> Determine applications regarding classifications where there is a dispute about an existing classification under this Agreement.</p><p><strong>74.2</strong> Panel</p><p><strong>(a)</strong> The Panel will comprise three persons being:</p><p><strong>(i)</strong> A nominee of the VHIA (on behalf of the Employers);</p><p><strong>(ii)</strong> A nominee of the HWU on behalf of the Employees; and</p><p><strong>(iii)</strong> an independent chairperson agreed by VHIA and the HWU or, in the absence of agreement, as nominated by the Minister for Health.</p><p><strong>(b)</strong> The Panel will commence to determine the matter within 21 days of the application and conclude its deliberations within a further 21 days.</p><p><strong>(c)</strong> No nominee on the Panel may be involved in a matter if they are directly affected by or are personally interested in the outcome.</p><p><strong>(d)</strong> The Panel shall act independently of the VHIA and the HWU.</p><p><strong>(e)</strong> The Panel chairperson shall act as an independent third party in deliberations of the Panel.</p><p><strong>(f)</strong> The Parties to an application to the Panel bear their own costs (save for the chairperson).</p><p><strong>(g)</strong> The Panel shall be responsible for determining its own procedure, provided that the procedure shall be consistent with the requirements of this clause 74, and shall adopt an inquisitorial procedure (rather than an adversarial procedure).</p><p><strong>74.3</strong> Application to Panel where there is a dispute regarding an existing classification</p><p><strong>(a)</strong> Either an Employer or an Employee (or their representatives) may make an application to the Panel regarding a dispute about an Employee’s classification where the Parties have attempted to resolve the dispute at the workplace as described at <a href="/eba/ebas/has-managers-admin/common-terms/consultation-disputes/17-dispute-resolution-procedure.html">Clause 17.4</a> and met the obligations set out at <a href="/eba/ebas/has-managers-admin/common-terms/consultation-disputes/17-dispute-resolution-procedure.html">Clause 17.2</a>.</p><p><strong>(b)</strong> Where an application is made to the Panel the terms of <a href="/eba/ebas/has-managers-admin/common-terms/consultation-disputes/17-dispute-resolution-procedure.html">Clause 17</a> continue to apply.</p><p><strong>(c)</strong> An Employee who is a Party to the dispute will be released by the Employer from normal duties as is reasonably necessary to enable them to participate in this dispute settling procedure so long as it does not unduly affect the operations of the Employer.</p><p><strong>74.4</strong> Materials to be provided to the Panel for classification applications Where an application to the Panel is made under 74.3.</p><p><strong>(a)</strong> the Employer will provide the following materials (where available) as soon as practicable:</p><p><strong>(i)</strong> the position description of the role;</p><p><strong>(ii)</strong> mandatory and desirable post registration skills, knowledge and education;</p><p><strong>(iii)</strong> the grade proposed by the applicant and the comparator position/s used to determine the proposed grade;</p><p><strong>(iv)</strong> actual reporting lines relevant to the position/s;</p><p><strong>(v)</strong> outline of the existing organisational structure applicable to the position/s; and</p><p><strong>(vi)</strong> identification of EFT and skill mix (if any) that reports to the position/s; and</p><p><strong>(b)</strong> The Employer will ensure the Employee is given the opportunity to provide:</p><p><strong>(i)</strong> an outline of the skill, duties, responsibilities and education/qualification requirements (if any) underpinning the role;</p><p><strong>(ii)</strong> objective observations on any differences between the role and that described in the position description; and</p><p><strong>(iii)</strong> the Employer&#39;s response to the applicant&#39;s outline.</p><p><strong>74.5</strong> Role of the Panel in considering an application</p><p><strong>(a)</strong> In considering an application under 71.3, the Panel will:</p><p><strong>(i)</strong> determine classification applications by the inherent requirements of the position, not those of the individual; and,</p><p><strong>(ii)</strong> apply the classification descriptors of the Agreement.</p><p><strong>(b)</strong> The Panel may otherwise inform itself in any manner it sees fit including, in the case of a classification application under 74.3, by seeking the views of an expert advisor (who is not an employee of the health service subject of the application) agreed to by the Panel in relation to the classification matter under consideration.</p><p><strong>(c)</strong> The Employer or VHIA and the Employee/s and/or HWU can advocate to the Panel.</p><p><strong>(d)</strong> The Panel will determine applications by majority, with written reasons to be prepared by the Chairperson (including any dissenting decision or a summary of any dissenting decision) and provided to the parties. In the case of an application under 74.3, the Panel may determine to support the re-grading or substitute a different grade to the role.</p><p><strong>(e)</strong> A determination of the Panel will be considered binding unless either the HWU or VHIA make an application to have the determination reviewed by the Commission within 14 days of receiving written determination. For the avoidance of doubt, no activity under clause</p><p>74.5(b) constitutes a determination for the purposes of subclause 74.5(d).</p><p><strong>(f)</strong> An application to the Commission will include the application, determination, written reasons and supporting material.</p><p><strong>(g)</strong> On receipt of an application under this clause, the President of the Commission will appoint a member of the Commission to preside over the matter.</p><p><strong>(h)</strong> The Commission will be assisted by the Chairperson, who will explain their recommendation, the application and supporting material, and inform the Commission of the position of the HWU and the VHIA.</p><p><strong>(i)</strong> The Commission will adopt an inquisitorial procedure (rather than an adversarial procedure) and will in effect stand in the shoes of the Panel and determine whether the Panel decision under review was properly reached, and may substitute or uphold the existing determination. Any determination under this clause will be final and binding upon the parties, and will not be subject to an appeal of the Full Bench.</p><p><strong>74.6</strong> Additional role of the Chairperson in considering matters affecting a hospital/health service&#39;s funding</p><p><strong>(a)</strong> The HWU and VHIA recognise that the Victorian Government, represented by the DH, has an implied right to have its interests heard and considered in decisions of the Panel.</p><p><strong>(b)</strong> If a matter before the Panel under 74.3 may result in a requirement for additional funding to a hospital or health service (beyond what is currently provided under regular State budget mechanisms), the Chair will ensure that:</p><p><strong>(i)</strong> the DH has a fair opportunity to be heard by the Panel; and</p><p><strong>(ii)</strong> the DH&#39;s interests are given due consideration by the Panel in its decision-making.</p><p><strong>74.7</strong> Panel determinations</p><p><strong>(a)</strong> The Panel will notify the Employer (and Employee where applicable) of the outcome of the application in writing within 14 days of the decision.</p><p><strong>(b)</strong> In the case of an application under 74.3, the determined grade will apply from the date of the application or a later date determined by the Panel.</p><p><strong>(c)</strong> Until the determination of the Panel, the existing grade (where relevant) will continue to apply.</p><p>PART I – CLASSIFICATION AND STAFFING</p>',54)])])}const m=t(o,[["render",r]]);export{g as __pageData,m as default};
